import React, { useEffect, useState } from 'react';
import ProjectCard from './ProjectCard';
import { Project } from '../types';

const categories = [
  'All Projects',
  'Selected Work',
  'Narrative',
  'Music Videos',
  'Commercials',
  'Format Agnostic',
];

const placeholder = (n: number) => `https://via.placeholder.com/1200x675?text=Project+${n}`;

const placeholderProjects: Project[] = [
  {
    id: 'p1',
    title: "Little Simz 'Flood'",
    description: 'Short film / Selected Work',
    thumbnail: placeholder(1),
    link: '#',
    category: 'Selected Work',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  },
  {
    id: 'p2',
    title: "Epiclesis 'Short Film'",
    description: 'Short film / Narrative',
    thumbnail: placeholder(2),
    link: '#',
    category: 'Narrative',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  },
  {
    id: 'p3',
    title: "Moeder 'Short Film'",
    description: 'Short film / Narrative',
    thumbnail: placeholder(3),
    link: '#',
    category: 'Narrative',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  },
  {
    id: 'p4',
    title: "HP 'The Wrong Kind of Busy'",
    description: 'Commercial',
    thumbnail: placeholder(4),
    link: '#',
    category: 'Commercials',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  },
  {
    id: 'p5',
    title: "Young Fathers 'Mr. Martyr'",
    description: 'Music video',
    thumbnail: placeholder(5),
    link: '#',
    category: 'Music Videos',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  },
  {
    id: 'p6',
    title: "NBA 'Don't Miss a Thing'",
    description: 'Commercial / Sports',
    thumbnail: placeholder(6),
    link: '#',
    category: 'Commercials',
    createdAt: new Date(),
    updatedAt: new Date(),
  },
  {
    id: 'p7',
    title: "Beyond the Endless Light",
    description: 'Selected Work',
    thumbnail: placeholder(7),
    link: '#',
    category: 'Selected Work',
    createdAt: new Date(),
    updatedAt: new Date(),
  },
  {
    id: 'p8',
    title: "House of Diligence 'Documentary'",
    description: 'Documentary',
    thumbnail: placeholder(8),
    link: '#',
    category: 'Format Agnostic',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  },
];

const ProjectList: React.FC = () => {
  const [projects, setProjects] = useState<Project[]>(placeholderProjects);
  const [filteredProjects, setFilteredProjects] = useState<Project[]>(placeholderProjects);
  const [selectedCategory, setSelectedCategory] = useState<string>('All Projects');

  useEffect(() => {
    const fetchProjects = async () => {
      try {
        const response = await fetch('/api/projects'); // adjust if your API is elsewhere
        if (!response.ok) {
          console.warn('Projects API returned non-OK, using placeholders');
          return;
        }
        const data: Project[] = await response.json();
        if (Array.isArray(data) && data.length > 0) {
          setProjects(data);
          setFilteredProjects(data);
        } else {
          console.warn('No projects returned, keeping placeholders');
        }
      } catch (err) {
        console.warn('Failed to fetch projects, using placeholders', err);
      }
    };

    fetchProjects();
  }, []);

  useEffect(() => {
    if (selectedCategory === 'All Projects') {
      setFilteredProjects(projects);
    } else {
      setFilteredProjects(projects.filter(project => (project.category || 'Format Agnostic') === selectedCategory));
    }
  }, [selectedCategory, projects]);

  return (
    <div>
      <div className="flex space-x-4 mb-4">
        {categories.map((cat) => (
          <button
            key={cat}
            className={`cursor-pointer hover:opacity-60 ${selectedCategory === cat ? 'font-bold' : ''}`}
            onClick={() => setSelectedCategory(cat)}
          >
            {cat}
          </button>
        ))}
      </div>

      <section className="project-grid">
        {filteredProjects.map((project, index) => (
          <div className="project-card" key={project.id}>
            <div className="project-card-number">{String(index + 1).padStart(2, '0')}</div>
            <ProjectCard project={project} />
          </div>
        ))}
      </section>
    </div>
  );
};

export default ProjectList;
